INSERT INTO `cms_page` VALUES (1,'404 Not Found','2columns-right','Page keywords','Page description','no-route','Whoops, our bad...','<dl>\r\n<dt>The page you requested was not found, and we have a fine guess why.</dt>\r\n<dd>\r\n<ul class=\"disc\">\r\n<li>If you typed the URL directly, please make sure the spelling is correct.</li>\r\n<li>If you clicked on a link to get here, the link is outdated.</li>\r\n</ul></dd>\r\n</dl>\r\n<dl>\r\n<dt>What can you do?</dt>\r\n<dd>Have no fear, help is near! There are many ways you can get back on track with Magento Store.</dd>\r\n<dd>\r\n<ul class=\"disc\">\r\n<li><a href=\"#\" onclick=\"history.go(-1); return false;\">Go back</a> to the previous page.</li>\r\n<li>Use the search bar at the top of the page to search for your products.</li>\r\n<li>Follow these links to get you back on track!<br /><a href=\"{{store url=\"\"}}\">Store Home</a> <span class=\"separator\">|</span> <a href=\"{{store url=\"customer/account\"}}\">My Account</a></li></ul></dd></dl>\r\n','2026-03-13 16:07:02','2026-03-13 16:07:02',1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),(2,'Home page','cms-full-width','thời trang, áo nam, áo nữ, quần, giày, túi xách, fashionstore','FashionStore - Cửa hàng thời trang cao cấp với đa dạng sản phẩm áo, quần, giày dép, túi xách. Giao hàng toàn quốc, đổi trả 30 ngày.','home','Home Page','<div class=\"full-width\" data-content-type=\"html\" data-appearance=\"default\" data-element=\"main\">&lt;style&gt;\r\n@import url(\'https://fonts.googleapis.com/css2?family=Cormorant+Garamond:wght@300;400;500;600&amp;family=Montserrat:wght@200;300;400;500&amp;display=swap\');\r\n\r\n* { margin: 0; padding: 0; box-sizing: border-box; }\r\n\r\n.dior-home {\r\n    font-family: \'Montserrat\', sans-serif;\r\n    color: #1a1a1a;\r\n    background: #fff;\r\n}\r\n\r\n/* HERO */\r\n.dior-hero {\r\n    position: relative;\r\n    height: 100vh;\r\n    background: #1a1a1a;\r\n    display: flex;\r\n    align-items: center;\r\n    justify-content: center;\r\n    overflow: hidden;\r\n}\r\n\r\n.dior-hero-bg {\r\n    position: absolute;\r\n    inset: 0;\r\n    background: linear-gradient(135deg, #1a1a1a 0%, #2d2d2d 50%, #1a1a1a 100%);\r\n}\r\n\r\n.dior-hero-content {\r\n    position: relative;\r\n    text-align: center;\r\n    color: #fff;\r\n    z-index: 2;\r\n}\r\n\r\n.dior-hero-subtitle {\r\n    font-family: \'Montserrat\', sans-serif;\r\n    font-size: 11px;\r\n    letter-spacing: 6px;\r\n    text-transform: uppercase;\r\n    color: #c9a96e;\r\n    margin-bottom: 24px;\r\n}\r\n\r\n.dior-hero-title {\r\n    font-family: \'Cormorant Garamond\', serif;\r\n    font-size: clamp(60px, 10vw, 120px);\r\n    font-weight: 300;\r\n    letter-spacing: 15px;\r\n    text-transform: uppercase;\r\n    line-height: 1;\r\n    margin-bottom: 32px;\r\n}\r\n\r\n.dior-hero-desc {\r\n    font-size: 12px;\r\n    letter-spacing: 3px;\r\n    text-transform: uppercase;\r\n    color: #ccc;\r\n    margin-bottom: 48px;\r\n}\r\n\r\n.dior-btn {\r\n    display: inline-block;\r\n    padding: 16px 48px;\r\n    border: 1px solid #c9a96e;\r\n    color: #c9a96e;\r\n    font-size: 10px;\r\n    letter-spacing: 4px;\r\n    text-transform: uppercase;\r\n    text-decoration: none;\r\n    transition: all 0.4s ease;\r\n    cursor: pointer;\r\n    background: transparent;\r\n}\r\n\r\n.dior-btn:hover {\r\n    background: #c9a96e;\r\n    color: #1a1a1a;\r\n}\r\n\r\n.dior-btn-dark {\r\n    border-color: #1a1a1a;\r\n    color: #1a1a1a;\r\n}\r\n\r\n.dior-btn-dark:hover {\r\n    background: #1a1a1a;\r\n    color: #fff;\r\n}\r\n\r\n/* MARQUEE */\r\n.dior-marquee {\r\n    background: #c9a96e;\r\n    padding: 14px 0;\r\n    overflow: hidden;\r\n    white-space: nowrap;\r\n}\r\n\r\n.dior-marquee-text {\r\n    display: inline-block;\r\n    animation: marquee 20s linear infinite;\r\n    font-size: 10px;\r\n    letter-spacing: 4px;\r\n    text-transform: uppercase;\r\n    color: #fff;\r\n}\r\n\r\n@keyframes marquee {\r\n    0% { transform: translateX(0); }\r\n    100% { transform: translateX(-50%); }\r\n}\r\n\r\n/* SECTION */\r\n.dior-section {\r\n    padding: 100px 60px;\r\n}\r\n\r\n.dior-section-title {\r\n    font-family: \'Cormorant Garamond\', serif;\r\n    font-size: clamp(36px, 5vw, 64px);\r\n    font-weight: 300;\r\n    letter-spacing: 8px;\r\n    text-transform: uppercase;\r\n    text-align: center;\r\n    margin-bottom: 16px;\r\n}\r\n\r\n.dior-section-sub {\r\n    text-align: center;\r\n    font-size: 10px;\r\n    letter-spacing: 4px;\r\n    text-transform: uppercase;\r\n    color: #999;\r\n    margin-bottom: 60px;\r\n}\r\n\r\n/* CATEGORIES GRID */\r\n.dior-grid {\r\n    display: grid;\r\n    grid-template-columns: repeat(3, 1fr);\r\n    gap: 2px;\r\n}\r\n\r\n.dior-grid-item {\r\n    position: relative;\r\n    overflow: hidden;\r\n    aspect-ratio: 3/4;\r\n    background: #f5f5f5;\r\n    cursor: pointer;\r\n}\r\n\r\n.dior-grid-item:first-child {\r\n    grid-row: span 2;\r\n    aspect-ratio: auto;\r\n}\r\n\r\n.dior-grid-bg {\r\n    width: 100%;\r\n    height: 100%;\r\n    object-fit: cover;\r\n    transition: transform 0.8s ease;\r\n}\r\n\r\n.dior-grid-item:hover .dior-grid-bg {\r\n    transform: scale(1.05);\r\n}\r\n\r\n.dior-grid-overlay {\r\n    position: absolute;\r\n    inset: 0;\r\n    background: linear-gradient(to top, rgba(0,0,0,0.7) 0%, transparent 60%);\r\n    display: flex;\r\n    flex-direction: column;\r\n    justify-content: flex-end;\r\n    padding: 32px;\r\n    color: #fff;\r\n}\r\n\r\n.dior-grid-label {\r\n    font-size: 9px;\r\n    letter-spacing: 4px;\r\n    text-transform: uppercase;\r\n    color: #c9a96e;\r\n    margin-bottom: 8px;\r\n}\r\n\r\n.dior-grid-name {\r\n    font-family: \'Cormorant Garamond\', serif;\r\n    font-size: 28px;\r\n    font-weight: 300;\r\n    letter-spacing: 4px;\r\n    text-transform: uppercase;\r\n}\r\n\r\n/* FEATURED - 2 columns */\r\n.dior-featured {\r\n    display: grid;\r\n    grid-template-columns: 1fr 1fr;\r\n    gap: 40px;\r\n    align-items: center;\r\n    padding: 100px 60px;\r\n    background: #f8f8f6;\r\n}\r\n\r\n.dior-featured-img {\r\n    aspect-ratio: 3/4;\r\n    background: linear-gradient(135deg, #e8e0d5, #d4c9ba);\r\n    display: flex;\r\n    align-items: center;\r\n    justify-content: center;\r\n    overflow: hidden;\r\n}\r\n\r\n.dior-featured-img-placeholder {\r\n    font-family: \'Cormorant Garamond\', serif;\r\n    font-size: 80px;\r\n    color: rgba(255,255,255,0.5);\r\n    font-weight: 300;\r\n}\r\n\r\n.dior-featured-content {\r\n    padding: 40px;\r\n}\r\n\r\n.dior-featured-label {\r\n    font-size: 9px;\r\n    letter-spacing: 5px;\r\n    text-transform: uppercase;\r\n    color: #c9a96e;\r\n    margin-bottom: 24px;\r\n}\r\n\r\n.dior-featured-title {\r\n    font-family: \'Cormorant Garamond\', serif;\r\n    font-size: 48px;\r\n    font-weight: 300;\r\n    letter-spacing: 4px;\r\n    text-transform: uppercase;\r\n    line-height: 1.2;\r\n    margin-bottom: 24px;\r\n}\r\n\r\n.dior-featured-desc {\r\n    font-size: 12px;\r\n    line-height: 2;\r\n    color: #666;\r\n    margin-bottom: 40px;\r\n    letter-spacing: 1px;\r\n}\r\n\r\n/* PRODUCTS */\r\n.dior-products {\r\n    display: grid;\r\n    grid-template-columns: repeat(4, 1fr);\r\n    gap: 24px;\r\n}\r\n\r\n.dior-product {\r\n    cursor: pointer;\r\n}\r\n\r\n.dior-product-img {\r\n    aspect-ratio: 3/4;\r\n    background: linear-gradient(135deg, #f0ebe4, #e8e0d5);\r\n    margin-bottom: 16px;\r\n    overflow: hidden;\r\n    position: relative;\r\n}\r\n\r\n.dior-product-img-placeholder {\r\n    width: 100%;\r\n    height: 100%;\r\n    display: flex;\r\n    align-items: center;\r\n    justify-content: center;\r\n    font-family: \'Cormorant Garamond\', serif;\r\n    font-size: 40px;\r\n    color: rgba(180,160,140,0.5);\r\n    transition: transform 0.6s ease;\r\n}\r\n\r\n.dior-product:hover .dior-product-img-placeholder {\r\n    transform: scale(1.05);\r\n}\r\n\r\n.dior-product-label {\r\n    font-size: 8px;\r\n    letter-spacing: 3px;\r\n    text-transform: uppercase;\r\n    color: #c9a96e;\r\n    margin-bottom: 6px;\r\n}\r\n\r\n.dior-product-name {\r\n    font-family: \'Cormorant Garamond\', serif;\r\n    font-size: 18px;\r\n    font-weight: 400;\r\n    letter-spacing: 2px;\r\n    margin-bottom: 6px;\r\n}\r\n\r\n.dior-product-price {\r\n    font-size: 11px;\r\n    letter-spacing: 2px;\r\n    color: #666;\r\n}\r\n\r\n/* BANNER */\r\n.dior-banner {\r\n    height: 60vh;\r\n    background: linear-gradient(135deg, #1a1a1a, #2d2d2d);\r\n    display: flex;\r\n    align-items: center;\r\n    justify-content: center;\r\n    text-align: center;\r\n    color: #fff;\r\n}\r\n\r\n.dior-banner-title {\r\n    font-family: \'Cormorant Garamond\', serif;\r\n    font-size: clamp(40px, 6vw, 80px);\r\n    font-weight: 300;\r\n    letter-spacing: 10px;\r\n    text-transform: uppercase;\r\n    margin-bottom: 24px;\r\n}\r\n\r\n/* VALUES */\r\n.dior-values {\r\n    display: grid;\r\n    grid-template-columns: repeat(3, 1fr);\r\n    gap: 60px;\r\n    padding: 100px 60px;\r\n    text-align: center;\r\n}\r\n\r\n.dior-value-icon {\r\n    font-size: 32px;\r\n    margin-bottom: 20px;\r\n    color: #c9a96e;\r\n}\r\n\r\n.dior-value-title {\r\n    font-family: \'Cormorant Garamond\', serif;\r\n    font-size: 22px;\r\n    letter-spacing: 4px;\r\n    text-transform: uppercase;\r\n    margin-bottom: 16px;\r\n}\r\n\r\n.dior-value-desc {\r\n    font-size: 11px;\r\n    line-height: 2;\r\n    color: #888;\r\n    letter-spacing: 1px;\r\n}\r\n\r\n/* DIVIDER */\r\n.dior-divider {\r\n    text-align: center;\r\n    padding: 40px;\r\n    font-family: \'Cormorant Garamond\', serif;\r\n    font-size: 24px;\r\n    color: #c9a96e;\r\n    letter-spacing: 8px;\r\n}\r\n\r\n@media (max-width: 768px) {\r\n    .dior-grid { grid-template-columns: 1fr 1fr; }\r\n    .dior-grid-item:first-child { grid-row: span 1; }\r\n    .dior-featured { grid-template-columns: 1fr; }\r\n    .dior-products { grid-template-columns: repeat(2, 1fr); }\r\n    .dior-values { grid-template-columns: 1fr; gap: 40px; }\r\n    .dior-section { padding: 60px 24px; }\r\n}\r\n&lt;/style&gt;\r\n\r\n&lt;div class=\"dior-home\"&gt;\r\n\r\n    &lt;!-- HERO --&gt;\r\n    &lt;div class=\"dior-hero\"&gt;\r\n        &lt;div class=\"dior-hero-bg\"&gt;&lt;/div&gt;\r\n        &lt;div class=\"dior-hero-content\"&gt;\r\n            &lt;p class=\"dior-hero-subtitle\"&gt;Bộ Sưu Tập Mới 2024&lt;/p&gt;\r\n            &lt;h1 class=\"dior-hero-title\"&gt;Fashion&lt;br&gt;Store&lt;/h1&gt;\r\n            &lt;p class=\"dior-hero-desc\"&gt;Thời Trang Cao Cấp · Phong Cách Đẳng Cấp&lt;/p&gt;\r\n            &lt;a href=\"/collections\" class=\"dior-btn\"&gt;Khám Phá Ngay&lt;/a&gt;\r\n        &lt;/div&gt;\r\n    &lt;/div&gt;\r\n\r\n    &lt;!-- MARQUEE --&gt;\r\n    &lt;div class=\"dior-marquee\"&gt;\r\n        &lt;span class=\"dior-marquee-text\"&gt;\r\n            ✦ THỜI TRANG CAO CẤP &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ PHONG CÁCH ĐẲng CẤP &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ CHẤT LƯỢNG VƯỢT TRỘI &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ GIAO HÀNG TOÀN QUỐC &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ ĐỔI TRẢ 30 NGÀY &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ THỜI TRANG CAO CẤP &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ PHONG CÁCH ĐẲNG CẤP &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ CHẤT LƯỢNG VƯỢT TRỘI &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ GIAO HÀNG TOÀN QUỐC &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ ĐỔI TRẢ 30 NGÀY &amp;nbsp;&amp;nbsp;&amp;nbsp;\r\n        &lt;/span&gt;\r\n    &lt;/div&gt;\r\n\r\n   &lt;!-- CATEGORIES --&gt;\r\n&lt;div class=\"dior-section\"&gt;\r\n    &lt;p class=\"dior-section-sub\"&gt;Danh Mục Sản Phẩm&lt;/p&gt;\r\n    &lt;h2 class=\"dior-section-title\"&gt;Bộ Sưu Tập&lt;/h2&gt;\r\n    &lt;div class=\"dior-grid\"&gt;\r\n\r\n        &lt;div class=\"dior-grid-item\" onclick=\"window.location=\'/ao-n.html\'\" style=\"cursor:pointer; grid-row: span 2;\"&gt;\r\n            &lt;div class=\"dior-grid-bg\" style=\"background: linear-gradient(135deg, #2d2d2d, #1a1a1a); height:100%; display:flex; align-items:center; justify-content:center;\"&gt;\r\n                &lt;span style=\"font-family:\'Cormorant Garamond\',serif; font-size:100px; color:rgba(201,169,110,0.3);\"&gt;♀&lt;/span&gt;\r\n            &lt;/div&gt;\r\n            &lt;div class=\"dior-grid-overlay\"&gt;\r\n                &lt;span class=\"dior-grid-label\"&gt;Thời Trang&lt;/span&gt;\r\n                &lt;span class=\"dior-grid-name\"&gt;Áo Nữ&lt;/span&gt;\r\n            &lt;/div&gt;\r\n        &lt;/div&gt;\r\n\r\n        &lt;div class=\"dior-grid-item\" onclick=\"window.location=\'/ao-nam.html\'\" style=\"cursor:pointer;\"&gt;\r\n            &lt;div class=\"dior-grid-bg\" style=\"background: linear-gradient(135deg, #3d3d3d, #2a2a2a); height:100%; display:flex; align-items:center; justify-content:center;\"&gt;\r\n                &lt;span style=\"font-family:\'Cormorant Garamond\',serif; font-size:80px; color:rgba(201,169,110,0.3);\"&gt;♂&lt;/span&gt;\r\n            &lt;/div&gt;\r\n            &lt;div class=\"dior-grid-overlay\"&gt;\r\n                &lt;span class=\"dior-grid-label\"&gt;Thời Trang&lt;/span&gt;\r\n                &lt;span class=\"dior-grid-name\"&gt;Áo Nam&lt;/span&gt;\r\n            &lt;/div&gt;\r\n        &lt;/div&gt;\r\n\r\n        &lt;div class=\"dior-grid-item\" onclick=\"window.location=\'/tui-xach.html\'\" style=\"cursor:pointer;\"&gt;\r\n            &lt;div class=\"dior-grid-bg\" style=\"background: linear-gradient(135deg, #c9a96e, #b8954a); height:100%; display:flex; align-items:center; justify-content:center;\"&gt;\r\n                &lt;span style=\"font-family:\'Cormorant Garamond\',serif; font-size:80px; color:rgba(255,255,255,0.3);\"&gt;&lt;/span&gt;\r\n            &lt;/div&gt;\r\n            &lt;div class=\"dior-grid-overlay\"&gt;\r\n                &lt;span class=\"dior-grid-label\"&gt;Phụ Kiện&lt;/span&gt;\r\n                &lt;span class=\"dior-grid-name\"&gt;Túi Xách&lt;/span&gt;\r\n            &lt;/div&gt;\r\n        &lt;/div&gt;\r\n\r\n        &lt;div class=\"dior-grid-item\" onclick=\"window.location=\'/giay-nam.html\'\" style=\"cursor:pointer;\"&gt;\r\n            &lt;div class=\"dior-grid-bg\" style=\"background: linear-gradient(135deg, #4a4a4a, #333); height:100%; display:flex; align-items:center; justify-content:center;\"&gt;\r\n                &lt;span style=\"font-family:\'Cormorant Garamond\',serif; font-size:80px; color:rgba(201,169,110,0.3);\"&gt;&lt;/span&gt;\r\n            &lt;/div&gt;\r\n            &lt;div class=\"dior-grid-overlay\"&gt;\r\n                &lt;span class=\"dior-grid-label\"&gt;Thời Trang&lt;/span&gt;\r\n                &lt;span class=\"dior-grid-name\"&gt;Giày Nam&lt;/span&gt;\r\n            &lt;/div&gt;\r\n        &lt;/div&gt;\r\n\r\n    &lt;/div&gt;\r\n&lt;/div&gt;\r\n\r\n    &lt;!-- FEATURED --&gt;\r\n    &lt;div class=\"dior-featured\"&gt;\r\n        &lt;div class=\"dior-featured-img\"&gt;\r\n            &lt;div class=\"dior-featured-img-placeholder\"&gt;✦&lt;/div&gt;\r\n        &lt;/div&gt;\r\n        &lt;div class=\"dior-featured-content\"&gt;\r\n            &lt;p class=\"dior-featured-label\"&gt;Nổi Bật · Mùa Thu Đông 2024&lt;/p&gt;\r\n            &lt;h2 class=\"dior-featured-title\"&gt;Bộ Sưu Tập&lt;br&gt;Đặc Biệt&lt;/h2&gt;\r\n            &lt;p class=\"dior-featured-desc\"&gt;\r\n                Được lấy cảm hứng từ vẻ đẹp tinh tế và sang trọng, \r\n                bộ sưu tập mùa thu đông 2024 mang đến những thiết kế \r\n                độc đáo, kết hợp hoàn hảo giữa truyền thống và hiện đại.\r\n            &lt;/p&gt;\r\n            &lt;a href=\"/ao-n.html\" class=\"dior-btn dior-btn-dark\"&gt;Xem Bộ Sưu Tập&lt;/a&gt;\r\n        &lt;/div&gt;\r\n    &lt;/div&gt;\r\n\r\n    &lt;!-- DIVIDER --&gt;\r\n    &lt;div class=\"dior-divider\"&gt;✦ &amp;nbsp;&amp;nbsp; Sản Phẩm Nổi Bật &amp;nbsp;&amp;nbsp; ✦&lt;/div&gt;\r\n\r\n    &lt;!-- PRODUCTS --&gt;\r\n    &lt;div class=\"dior-section\"&gt;\r\n        &lt;div class=\"dior-products\"&gt;\r\n            &lt;div class=\"dior-product\"&gt;\r\n                &lt;div class=\"dior-product-img\"&gt;\r\n                    &lt;div class=\"dior-product-img-placeholder\"&gt;①&lt;/div&gt;\r\n                &lt;/div&gt;\r\n                &lt;p class=\"dior-product-label\"&gt;Áo Nữ&lt;/p&gt;\r\n                &lt;p class=\"dior-product-name\"&gt;Áo Blazer Nữ Đen&lt;/p&gt;\r\n                &lt;p class=\"dior-product-price\"&gt;699.000 ₫&lt;/p&gt;\r\n            &lt;/div&gt;\r\n            &lt;div class=\"dior-product\"&gt;\r\n                &lt;div class=\"dior-product-img\"&gt;\r\n                    &lt;div class=\"dior-product-img-placeholder\"&gt;②&lt;/div&gt;\r\n                &lt;/div&gt;\r\n                &lt;p class=\"dior-product-label\"&gt;Túi Xách&lt;/p&gt;\r\n                &lt;p class=\"dior-product-name\"&gt;Túi Xách Da Đen&lt;/p&gt;\r\n                &lt;p class=\"dior-product-price\"&gt;1.299.000 ₫&lt;/p&gt;\r\n            &lt;/div&gt;\r\n            &lt;div class=\"dior-product\"&gt;\r\n                &lt;div class=\"dior-product-img\"&gt;\r\n                    &lt;div class=\"dior-product-img-placeholder\"&gt;③&lt;/div&gt;\r\n                &lt;/div&gt;\r\n                &lt;p class=\"dior-product-label\"&gt;Giày Nữ&lt;/p&gt;\r\n                &lt;p class=\"dior-product-name\"&gt;Giày Cao Gót Đen&lt;/p&gt;\r\n                &lt;p class=\"dior-product-price\"&gt;899.000 ₫&lt;/p&gt;\r\n            &lt;/div&gt;\r\n            &lt;div class=\"dior-product\"&gt;\r\n                &lt;div class=\"dior-product-img\"&gt;\r\n                    &lt;div class=\"dior-product-img-placeholder\"&gt;④&lt;/div&gt;\r\n                &lt;/div&gt;\r\n                &lt;p class=\"dior-product-label\"&gt;Váy &amp; Đầm&lt;/p&gt;\r\n                &lt;p class=\"dior-product-name\"&gt;Đầm Dự Tiệc Đỏ&lt;/p&gt;\r\n                &lt;p class=\"dior-product-price\"&gt;899.000 ₫&lt;/p&gt;\r\n            &lt;/div&gt;\r\n        &lt;/div&gt;\r\n    &lt;/div&gt;\r\n\r\n    &lt;!-- BANNER --&gt;\r\n    &lt;div class=\"dior-banner\"&gt;\r\n        &lt;div&gt;\r\n            &lt;h2 class=\"dior-banner-title\"&gt;Ưu Đãi Đặc Biệt&lt;/h2&gt;\r\n            &lt;p style=\"font-size:11px; letter-spacing:4px; color:#c9a96e; margin-bottom:32px; text-transform:uppercase;\"&gt;Giảm Đến 50% · Hàng Sale&lt;/p&gt;\r\n            &lt;a href=\"/hang-sale.html\" class=\"dior-btn\"&gt;Mua Ngay&lt;/a&gt;\r\n        &lt;/div&gt;\r\n    &lt;/div&gt;\r\n\r\n    &lt;!-- VALUES --&gt;\r\n    &lt;div class=\"dior-values\"&gt;\r\n        &lt;div&gt;\r\n            &lt;div class=\"dior-value-icon\"&gt;✦&lt;/div&gt;\r\n            &lt;h3 class=\"dior-value-title\"&gt;Chất Lượng Cao Cấp&lt;/h3&gt;\r\n            &lt;p class=\"dior-value-desc\"&gt;Mỗi sản phẩm được chọn lọc kỹ càng từ những chất liệu cao cấp nhất, mang đến sự thoải mái và sang trọng tuyệt đối.&lt;/p&gt;\r\n        &lt;/div&gt;\r\n        &lt;div&gt;\r\n            &lt;div class=\"dior-value-icon\"&gt;◈&lt;/div&gt;\r\n            &lt;h3 class=\"dior-value-title\"&gt;Giao Hàng Toàn Quốc&lt;/h3&gt;\r\n            &lt;p class=\"dior-value-desc\"&gt;Dịch vụ giao hàng nhanh chóng, an toàn đến tận tay khách hàng trên toàn quốc trong vòng 2-3 ngày làm việc.&lt;/p&gt;\r\n        &lt;/div&gt;\r\n        &lt;div&gt;\r\n            &lt;div class=\"dior-value-icon\"&gt;◇&lt;/div&gt;\r\n            &lt;h3 class=\"dior-value-title\"&gt;Đổi Trả 30 Ngày&lt;/h3&gt;\r\n            &lt;p class=\"dior-value-desc\"&gt;Chính sách đổi trả linh hoạt trong 30 ngày, đảm bảo sự hài lòng tuyệt đối của khách hàng với mọi sản phẩm.&lt;/p&gt;\r\n        &lt;/div&gt;\r\n    &lt;/div&gt;\r\n\r\n&lt;/div&gt;\r\n</div>','2026-03-13 16:07:02','2026-03-19 15:46:15',1,0,'<!--\n    <referenceContainer name=\"right\">\n        <referenceBlock name=\"catalog.compare.sidebar\" remove=\"true\" />\n    </referenceContainer>-->','','',NULL,NULL,NULL,NULL,'FashionStore - Thời Trang Cao Cấp Giá Rẻ'),(3,'Enable Cookies','1column',NULL,NULL,'enable-cookies','What are Cookies?','<div class=\"enable-cookies cms-content\">\r\n<p>\"Cookies\" are little pieces of data we send when you visit our store. Cookies help us get to know you better and personalize your experience. Plus they help protect you and other shoppers from fraud.</p>\r\n<p style=\"margin-bottom: 20px;\">Set your browser to accept cookies so you can buy items, save items, and receive customized recommendations. Here’s how:</p>\r\n<ul>\r\n<li><a href=\"https://support.google.com/accounts/answer/61416?hl=en\" target=\"_blank\">Google Chrome</a></li>\r\n<li><a href=\"http://windows.microsoft.com/en-us/internet-explorer/delete-manage-cookies\" target=\"_blank\">Internet Explorer</a></li>\r\n<li><a href=\"http://support.apple.com/kb/PH19214\" target=\"_blank\">Safari</a></li>\r\n<li><a href=\"https://support.mozilla.org/en-US/kb/enable-and-disable-cookies-website-preferences\" target=\"_blank\">Mozilla/Firefox</a></li>\r\n</ul>\r\n</div>','2026-03-13 16:07:02','2026-03-13 16:07:02',1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),(4,'Privacy and Cookie Policy','1column',NULL,NULL,'privacy-policy-cookie-restriction-mode','Privacy and Cookie Policy','<div class=\"privacy-policy cms-content\">\n    <div class=\"message info\">\n        <span>\n            Please replace this text with you Privacy Policy.\n            Please add any additional cookies your website uses below (e.g. Google Analytics).\n        </span>\n    </div>\n    <p>\n        This privacy policy sets out how this website (hereafter \"the Store\") uses and protects any information that\n        you give the Store while using this website. The Store is committed to ensuring that your privacy is protected.\n        Should we ask you to provide certain information by which you can be identified when using this website, then\n        you can be assured that it will only be used in accordance with this privacy statement. The Store may change\n        this policy from time to time by updating this page. You should check this page from time to time to ensure\n        that you are happy with any changes.\n    </p>\n    <h2>What we collect</h2>\n    <p>We may collect the following information:</p>\n    <ul>\n        <li>name</li>\n        <li>contact information including email address</li>\n        <li>demographic information such as postcode, preferences and interests</li>\n        <li>other information relevant to customer surveys and/or offers</li>\n    </ul>\n    <p>\n        For the exhaustive list of cookies we collect see the <a href=\"#list\">List of cookies we collect</a> section.\n    </p>\n    <h2>What we do with the information we gather</h2>\n    <p>\n        We require this information to understand your needs and provide you with a better service,\n        and in particular for the following reasons:\n    </p>\n    <ul>\n        <li>Internal record keeping.</li>\n        <li>We may use the information to improve our products and services.</li>\n        <li>\n            We may periodically send promotional emails about new products, special offers or other information which we\n            think you may find interesting using the email address which you have provided.\n        </li>\n        <li>\n            From time to time, we may also use your information to contact you for market research purposes.\n            We may contact you by email, phone, fax or mail. We may use the information to customise the website\n            according to your interests.\n        </li>\n    </ul>\n    <h2>Security</h2>\n    <p>\n        We are committed to ensuring that your information is secure. In order to prevent unauthorised access or\n        disclosure, we have put in place suitable physical, electronic and managerial procedures to safeguard and\n        secure the information we collect online.\n    </p>\n    <h2>How we use cookies</h2>\n    <p>\n        A cookie is a small file which asks permission to be placed on your computer\'s hard drive.\n        Once you agree, the file is added and the cookie helps analyse web traffic or lets you know when you visit\n        a particular site. Cookies allow web applications to respond to you as an individual. The web application\n        can tailor its operations to your needs, likes and dislikes by gathering and remembering information about\n        your preferences.\n    </p>\n    <p>\n        We use traffic log cookies to identify which pages are being used. This helps us analyse data about web page\n        traffic and improve our website in order to tailor it to customer needs. We only use this information for\n        statistical analysis purposes and then the data is removed from the system.\n    </p>\n    <p>\n        Overall, cookies help us provide you with a better website, by enabling us to monitor which pages you find\n        useful and which you do not. A cookie in no way gives us access to your computer or any information about you,\n        other than the data you choose to share with us. You can choose to accept or decline cookies.\n        Most web browsers automatically accept cookies, but you can usually modify your browser setting\n        to decline cookies if you prefer. This may prevent you from taking full advantage of the website.\n    </p>\n    <h2>Links to other websites</h2>\n    <p>\n        Our website may contain links to other websites of interest. However, once you have used these links\n        to leave our site, you should note that we do not have any control over that other website.\n        Therefore, we cannot be responsible for the protection and privacy of any information which you provide whilst\n        visiting such sites and such sites are not governed by this privacy statement.\n        You should exercise caution and look at the privacy statement applicable to the website in question.\n    </p>\n    <h2>Controlling your personal information</h2>\n    <p>You may choose to restrict the collection or use of your personal information in the following ways:</p>\n    <ul>\n        <li>\n            whenever you are asked to fill in a form on the website, look for the box that you can click to indicate\n            that you do not want the information to be used by anybody for direct marketing purposes\n        </li>\n        <li>\n            if you have previously agreed to us using your personal information for direct marketing purposes,\n            you may change your mind at any time by letting us know using our Contact Us information\n        </li>\n    </ul>\n    <p>\n        We will not sell, distribute or lease your personal information to third parties unless we have your permission\n        or are required by law to do so. We may use your personal information to send you promotional information\n        about third parties which we think you may find interesting if you tell us that you wish this to happen.\n    </p>\n    <p>\n        You may request details of personal information which we hold about you under the Data Protection Act 1998.\n        A small fee will be payable. If you would like a copy of the information held on you please email us this\n        request using our Contact Us information.\n    </p>\n    <p>\n        If you believe that any information we are holding on you is incorrect or incomplete,\n        please write to or email us as soon as possible, at the above address.\n        We will promptly correct any information found to be incorrect.\n    </p>\n    <h2><a name=\"list\"></a>List of cookies we collect</h2>\n    <p>The table below lists the cookies we collect and what information they store.</p>\n    <table class=\"data-table data-table-definition-list\">\n        <thead>\n        <tr>\n            <th>Cookie Name</th>\n            <th>Cookie Description</th>\n        </tr>\n        </thead>\n        <tbody>\n            <tr>\n                <th>FORM_KEY</th>\n                <td>Stores randomly generated key used to prevent forged requests.</td>\n            </tr>\n            <tr>\n                <th>PHPSESSID</th>\n                <td>Your session ID on the server.</td>\n            </tr>\n            <tr>\n                <th>GUEST-VIEW</th>\n                <td>Allows guests to view and edit their orders.</td>\n            </tr>\n            <tr>\n                <th>PERSISTENT_SHOPPING_CART</th>\n                <td>A link to information about your cart and viewing history, if you have asked for this.</td>\n            </tr>\n            <tr>\n                <th>STF</th>\n                <td>Information on products you have emailed to friends.</td>\n            </tr>\n            <tr>\n                <th>STORE</th>\n                <td>The store view or language you have selected.</td>\n            </tr>\n            <tr>\n                <th>USER_ALLOWED_SAVE_COOKIE</th>\n                <td>Indicates whether a customer allowed to use cookies.</td>\n            </tr>\n            <tr>\n                <th>MAGE-CACHE-SESSID</th>\n                <td>Facilitates caching of content on the browser to make pages load faster.</td>\n            </tr>\n            <tr>\n                <th>MAGE-CACHE-STORAGE</th>\n                <td>Facilitates caching of content on the browser to make pages load faster.</td>\n            </tr>\n            <tr>\n                <th>MAGE-CACHE-STORAGE-SECTION-INVALIDATION</th>\n                <td>Facilitates caching of content on the browser to make pages load faster.</td>\n            </tr>\n            <tr>\n                <th>MAGE-CACHE-TIMEOUT</th>\n                <td>Facilitates caching of content on the browser to make pages load faster.</td>\n            </tr>\n            <tr>\n                <th>SECTION-DATA-IDS</th>\n                <td>Facilitates caching of content on the browser to make pages load faster.</td>\n            </tr>\n            <tr>\n                <th>PRIVATE_CONTENT_VERSION</th>\n                <td>Facilitates caching of content on the browser to make pages load faster.</td>\n            </tr>\n            <tr>\n                <th>X-MAGENTO-VARY</th>\n                <td>Facilitates caching of content on the server to make pages load faster.</td>\n            </tr>\n            <tr>\n                <th>MAGE-TRANSLATION-FILE-VERSION</th>\n                <td>Facilitates translation of content to other languages.</td>\n            </tr>\n            <tr>\n                <th>MAGE-TRANSLATION-STORAGE</th>\n                <td>Facilitates translation of content to other languages.</td>\n            </tr>\n        </tbody>\n    </table>\n</div>','2026-03-13 16:07:02','2026-03-13 16:07:03',1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
