INSERT INTO `pagebuilder_template` VALUES (3,'Test full width','.template-managertestfullwidth69bae291782f2.jpg','<div class=\"full-width\" data-content-type=\"html\" data-appearance=\"default\" data-element=\"main\">&lt;style&gt;\n@import url(\'https://fonts.googleapis.com/css2?family=Cormorant+Garamond:wght@300;400;500;600&amp;family=Montserrat:wght@200;300;400;500&amp;display=swap\');\n\n* { margin: 0; padding: 0; box-sizing: border-box; }\n\n.dior-home {\n    font-family: \'Montserrat\', sans-serif;\n    color: #1a1a1a;\n    background: #fff;\n}\n\n/* HERO */\n.dior-hero {\n    position: relative;\n    height: 100vh;\n    background: #1a1a1a;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    overflow: hidden;\n}\n\n.dior-hero-bg {\n    position: absolute;\n    inset: 0;\n    background: linear-gradient(135deg, #1a1a1a 0%, #2d2d2d 50%, #1a1a1a 100%);\n}\n\n.dior-hero-content {\n    position: relative;\n    text-align: center;\n    color: #fff;\n    z-index: 2;\n}\n\n.dior-hero-subtitle {\n    font-family: \'Montserrat\', sans-serif;\n    font-size: 11px;\n    letter-spacing: 6px;\n    text-transform: uppercase;\n    color: #c9a96e;\n    margin-bottom: 24px;\n}\n\n.dior-hero-title {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: clamp(60px, 10vw, 120px);\n    font-weight: 300;\n    letter-spacing: 15px;\n    text-transform: uppercase;\n    line-height: 1;\n    margin-bottom: 32px;\n}\n\n.dior-hero-desc {\n    font-size: 12px;\n    letter-spacing: 3px;\n    text-transform: uppercase;\n    color: #ccc;\n    margin-bottom: 48px;\n}\n\n.dior-btn {\n    display: inline-block;\n    padding: 16px 48px;\n    border: 1px solid #c9a96e;\n    color: #c9a96e;\n    font-size: 10px;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n    text-decoration: none;\n    transition: all 0.4s ease;\n    cursor: pointer;\n    background: transparent;\n}\n\n.dior-btn:hover {\n    background: #c9a96e;\n    color: #1a1a1a;\n}\n\n.dior-btn-dark {\n    border-color: #1a1a1a;\n    color: #1a1a1a;\n}\n\n.dior-btn-dark:hover {\n    background: #1a1a1a;\n    color: #fff;\n}\n\n/* MARQUEE */\n.dior-marquee {\n    background: #c9a96e;\n    padding: 14px 0;\n    overflow: hidden;\n    white-space: nowrap;\n}\n\n.dior-marquee-text {\n    display: inline-block;\n    animation: marquee 20s linear infinite;\n    font-size: 10px;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n    color: #fff;\n}\n\n@keyframes marquee {\n    0% { transform: translateX(0); }\n    100% { transform: translateX(-50%); }\n}\n\n/* SECTION */\n.dior-section {\n    padding: 100px 60px;\n}\n\n.dior-section-title {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: clamp(36px, 5vw, 64px);\n    font-weight: 300;\n    letter-spacing: 8px;\n    text-transform: uppercase;\n    text-align: center;\n    margin-bottom: 16px;\n}\n\n.dior-section-sub {\n    text-align: center;\n    font-size: 10px;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n    color: #999;\n    margin-bottom: 60px;\n}\n\n/* CATEGORIES GRID */\n.dior-grid {\n    display: grid;\n    grid-template-columns: repeat(3, 1fr);\n    gap: 2px;\n}\n\n.dior-grid-item {\n    position: relative;\n    overflow: hidden;\n    aspect-ratio: 3/4;\n    background: #f5f5f5;\n    cursor: pointer;\n}\n\n.dior-grid-item:first-child {\n    grid-row: span 2;\n    aspect-ratio: auto;\n}\n\n.dior-grid-bg {\n    width: 100%;\n    height: 100%;\n    object-fit: cover;\n    transition: transform 0.8s ease;\n}\n\n.dior-grid-item:hover .dior-grid-bg {\n    transform: scale(1.05);\n}\n\n.dior-grid-overlay {\n    position: absolute;\n    inset: 0;\n    background: linear-gradient(to top, rgba(0,0,0,0.7) 0%, transparent 60%);\n    display: flex;\n    flex-direction: column;\n    justify-content: flex-end;\n    padding: 32px;\n    color: #fff;\n}\n\n.dior-grid-label {\n    font-size: 9px;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n    color: #c9a96e;\n    margin-bottom: 8px;\n}\n\n.dior-grid-name {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 28px;\n    font-weight: 300;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n}\n\n/* FEATURED - 2 columns */\n.dior-featured {\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: 40px;\n    align-items: center;\n    padding: 100px 60px;\n    background: #f8f8f6;\n}\n\n.dior-featured-img {\n    aspect-ratio: 3/4;\n    background: linear-gradient(135deg, #e8e0d5, #d4c9ba);\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    overflow: hidden;\n}\n\n.dior-featured-img-placeholder {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 80px;\n    color: rgba(255,255,255,0.5);\n    font-weight: 300;\n}\n\n.dior-featured-content {\n    padding: 40px;\n}\n\n.dior-featured-label {\n    font-size: 9px;\n    letter-spacing: 5px;\n    text-transform: uppercase;\n    color: #c9a96e;\n    margin-bottom: 24px;\n}\n\n.dior-featured-title {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 48px;\n    font-weight: 300;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n    line-height: 1.2;\n    margin-bottom: 24px;\n}\n\n.dior-featured-desc {\n    font-size: 12px;\n    line-height: 2;\n    color: #666;\n    margin-bottom: 40px;\n    letter-spacing: 1px;\n}\n\n/* PRODUCTS */\n.dior-products {\n    display: grid;\n    grid-template-columns: repeat(4, 1fr);\n    gap: 24px;\n}\n\n.dior-product {\n    cursor: pointer;\n}\n\n.dior-product-img {\n    aspect-ratio: 3/4;\n    background: linear-gradient(135deg, #f0ebe4, #e8e0d5);\n    margin-bottom: 16px;\n    overflow: hidden;\n    position: relative;\n}\n\n.dior-product-img-placeholder {\n    width: 100%;\n    height: 100%;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 40px;\n    color: rgba(180,160,140,0.5);\n    transition: transform 0.6s ease;\n}\n\n.dior-product:hover .dior-product-img-placeholder {\n    transform: scale(1.05);\n}\n\n.dior-product-label {\n    font-size: 8px;\n    letter-spacing: 3px;\n    text-transform: uppercase;\n    color: #c9a96e;\n    margin-bottom: 6px;\n}\n\n.dior-product-name {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 18px;\n    font-weight: 400;\n    letter-spacing: 2px;\n    margin-bottom: 6px;\n}\n\n.dior-product-price {\n    font-size: 11px;\n    letter-spacing: 2px;\n    color: #666;\n}\n\n/* BANNER */\n.dior-banner {\n    height: 60vh;\n    background: linear-gradient(135deg, #1a1a1a, #2d2d2d);\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    text-align: center;\n    color: #fff;\n}\n\n.dior-banner-title {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: clamp(40px, 6vw, 80px);\n    font-weight: 300;\n    letter-spacing: 10px;\n    text-transform: uppercase;\n    margin-bottom: 24px;\n}\n\n/* VALUES */\n.dior-values {\n    display: grid;\n    grid-template-columns: repeat(3, 1fr);\n    gap: 60px;\n    padding: 100px 60px;\n    text-align: center;\n}\n\n.dior-value-icon {\n    font-size: 32px;\n    margin-bottom: 20px;\n    color: #c9a96e;\n}\n\n.dior-value-title {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 22px;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n    margin-bottom: 16px;\n}\n\n.dior-value-desc {\n    font-size: 11px;\n    line-height: 2;\n    color: #888;\n    letter-spacing: 1px;\n}\n\n/* DIVIDER */\n.dior-divider {\n    text-align: center;\n    padding: 40px;\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 24px;\n    color: #c9a96e;\n    letter-spacing: 8px;\n}\n\n@media (max-width: 768px) {\n    .dior-grid { grid-template-columns: 1fr 1fr; }\n    .dior-grid-item:first-child { grid-row: span 1; }\n    .dior-featured { grid-template-columns: 1fr; }\n    .dior-products { grid-template-columns: repeat(2, 1fr); }\n    .dior-values { grid-template-columns: 1fr; gap: 40px; }\n    .dior-section { padding: 60px 24px; }\n}\n&lt;/style&gt;\n\n&lt;div class=\"dior-home\"&gt;\n\n    &lt;!-- HERO --&gt;\n    &lt;div class=\"dior-hero\"&gt;\n        &lt;div class=\"dior-hero-bg\"&gt;&lt;/div&gt;\n        &lt;div class=\"dior-hero-content\"&gt;\n            &lt;p class=\"dior-hero-subtitle\"&gt;Bộ Sưu Tập Mới 2024&lt;/p&gt;\n            &lt;h1 class=\"dior-hero-title\"&gt;Fashion&lt;br&gt;Store&lt;/h1&gt;\n            &lt;p class=\"dior-hero-desc\"&gt;Thời Trang Cao Cấp · Phong Cách Đẳng Cấp&lt;/p&gt;\n            &lt;a href=\"/collections\" class=\"dior-btn\"&gt;Khám Phá Ngay&lt;/a&gt;\n        &lt;/div&gt;\n    &lt;/div&gt;\n\n    &lt;!-- MARQUEE --&gt;\n    &lt;div class=\"dior-marquee\"&gt;\n        &lt;span class=\"dior-marquee-text\"&gt;\n            ✦ THỜI TRANG CAO CẤP &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ PHONG CÁCH ĐẲng CẤP &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ CHẤT LƯỢNG VƯỢT TRỘI &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ GIAO HÀNG TOÀN QUỐC &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ ĐỔI TRẢ 30 NGÀY &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ THỜI TRANG CAO CẤP &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ PHONG CÁCH ĐẲNG CẤP &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ CHẤT LƯỢNG VƯỢT TRỘI &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ GIAO HÀNG TOÀN QUỐC &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ ĐỔI TRẢ 30 NGÀY &amp;nbsp;&amp;nbsp;&amp;nbsp;\n        &lt;/span&gt;\n    &lt;/div&gt;\n\n    &lt;!-- CATEGORIES --&gt;\n    &lt;div class=\"dior-section\"&gt;\n        &lt;p class=\"dior-section-sub\"&gt;Danh Mục Sản Phẩm&lt;/p&gt;\n        &lt;h2 class=\"dior-section-title\"&gt;Bộ Sưu Tập&lt;/h2&gt;\n        &lt;div class=\"dior-grid\"&gt;\n            &lt;div class=\"dior-grid-item\"&gt;\n                &lt;div class=\"dior-grid-bg\" style=\"background: linear-gradient(135deg, #2d2d2d, #1a1a1a); height:100%; display:flex; align-items:center; justify-content:center;\"&gt;\n                    &lt;span style=\"font-family:\'Cormorant Garamond\',serif; font-size:100px; color:rgba(201,169,110,0.3);\"&gt;♀&lt;/span&gt;\n                &lt;/div&gt;\n                &lt;div class=\"dior-grid-overlay\"&gt;\n                    &lt;span class=\"dior-grid-label\"&gt;Thời Trang&lt;/span&gt;\n                    &lt;span class=\"dior-grid-name\"&gt;Áo Nữ&lt;/span&gt;\n                &lt;/div&gt;\n            &lt;/div&gt;\n            &lt;div class=\"dior-grid-item\"&gt;\n                &lt;div class=\"dior-grid-bg\" style=\"background: linear-gradient(135deg, #3d3d3d, #2a2a2a); height:100%; display:flex; align-items:center; justify-content:center;\"&gt;\n                    &lt;span style=\"font-family:\'Cormorant Garamond\',serif; font-size:80px; color:rgba(201,169,110,0.3);\"&gt;♂&lt;/span&gt;\n                &lt;/div&gt;\n                &lt;div class=\"dior-grid-overlay\"&gt;\n                    &lt;span class=\"dior-grid-label\"&gt;Thời Trang&lt;/span&gt;\n                    &lt;span class=\"dior-grid-name\"&gt;Áo Nam&lt;/span&gt;\n                &lt;/div&gt;\n            &lt;/div&gt;\n            &lt;div class=\"dior-grid-item\"&gt;\n                &lt;div class=\"dior-grid-bg\" style=\"background: linear-gradient(135deg, #c9a96e, #b8954a); height:100%; display:flex; align-items:center; justify-content:center;\"&gt;\n                    &lt;span style=\"font-family:\'Cormorant Garamond\',serif; font-size:80px; color:rgba(255,255,255,0.3);\"&gt;&lt;/span&gt;\n                &lt;/div&gt;\n                &lt;div class=\"dior-grid-overlay\"&gt;\n                    &lt;span class=\"dior-grid-label\"&gt;Phụ Kiện&lt;/span&gt;\n                    &lt;span class=\"dior-grid-name\"&gt;Túi Xách&lt;/span&gt;\n                &lt;/div&gt;\n            &lt;/div&gt;\n            &lt;div class=\"dior-grid-item\"&gt;\n                &lt;div class=\"dior-grid-bg\" style=\"background: linear-gradient(135deg, #4a4a4a, #333); height:100%; display:flex; align-items:center; justify-content:center;\"&gt;\n                    &lt;span style=\"font-family:\'Cormorant Garamond\',serif; font-size:80px; color:rgba(201,169,110,0.3);\"&gt;&lt;/span&gt;\n                &lt;/div&gt;\n                &lt;div class=\"dior-grid-overlay\"&gt;\n                    &lt;span class=\"dior-grid-label\"&gt;Thời Trang&lt;/span&gt;\n                    &lt;span class=\"dior-grid-name\"&gt;Giày Dép&lt;/span&gt;\n                &lt;/div&gt;\n            &lt;/div&gt;\n        &lt;/div&gt;\n    &lt;/div&gt;\n\n    &lt;!-- FEATURED --&gt;\n    &lt;div class=\"dior-featured\"&gt;\n        &lt;div class=\"dior-featured-img\"&gt;\n            &lt;div class=\"dior-featured-img-placeholder\"&gt;✦&lt;/div&gt;\n        &lt;/div&gt;\n        &lt;div class=\"dior-featured-content\"&gt;\n            &lt;p class=\"dior-featured-label\"&gt;Nổi Bật · Mùa Thu Đông 2024&lt;/p&gt;\n            &lt;h2 class=\"dior-featured-title\"&gt;Bộ Sưu Tập&lt;br&gt;Đặc Biệt&lt;/h2&gt;\n            &lt;p class=\"dior-featured-desc\"&gt;\n                Được lấy cảm hứng từ vẻ đẹp tinh tế và sang trọng, \n                bộ sưu tập mùa thu đông 2024 mang đến những thiết kế \n                độc đáo, kết hợp hoàn hảo giữa truyền thống và hiện đại.\n            &lt;/p&gt;\n            &lt;a href=\"/ao-nu.html\" class=\"dior-btn dior-btn-dark\"&gt;Xem Bộ Sưu Tập&lt;/a&gt;\n        &lt;/div&gt;\n    &lt;/div&gt;\n\n    &lt;!-- DIVIDER --&gt;\n    &lt;div class=\"dior-divider\"&gt;✦ &amp;nbsp;&amp;nbsp; Sản Phẩm Nổi Bật &amp;nbsp;&amp;nbsp; ✦&lt;/div&gt;\n\n    &lt;!-- PRODUCTS --&gt;\n    &lt;div class=\"dior-section\"&gt;\n        &lt;div class=\"dior-products\"&gt;\n            &lt;div class=\"dior-product\"&gt;\n                &lt;div class=\"dior-product-img\"&gt;\n                    &lt;div class=\"dior-product-img-placeholder\"&gt;①&lt;/div&gt;\n                &lt;/div&gt;\n                &lt;p class=\"dior-product-label\"&gt;Áo Nữ&lt;/p&gt;\n                &lt;p class=\"dior-product-name\"&gt;Áo Blazer Nữ Đen&lt;/p&gt;\n                &lt;p class=\"dior-product-price\"&gt;699.000 ₫&lt;/p&gt;\n            &lt;/div&gt;\n            &lt;div class=\"dior-product\"&gt;\n                &lt;div class=\"dior-product-img\"&gt;\n                    &lt;div class=\"dior-product-img-placeholder\"&gt;②&lt;/div&gt;\n                &lt;/div&gt;\n                &lt;p class=\"dior-product-label\"&gt;Túi Xách&lt;/p&gt;\n                &lt;p class=\"dior-product-name\"&gt;Túi Xách Da Đen&lt;/p&gt;\n                &lt;p class=\"dior-product-price\"&gt;1.299.000 ₫&lt;/p&gt;\n            &lt;/div&gt;\n            &lt;div class=\"dior-product\"&gt;\n                &lt;div class=\"dior-product-img\"&gt;\n                    &lt;div class=\"dior-product-img-placeholder\"&gt;③&lt;/div&gt;\n                &lt;/div&gt;\n                &lt;p class=\"dior-product-label\"&gt;Giày Nữ&lt;/p&gt;\n                &lt;p class=\"dior-product-name\"&gt;Giày Cao Gót Đen&lt;/p&gt;\n                &lt;p class=\"dior-product-price\"&gt;899.000 ₫&lt;/p&gt;\n            &lt;/div&gt;\n            &lt;div class=\"dior-product\"&gt;\n                &lt;div class=\"dior-product-img\"&gt;\n                    &lt;div class=\"dior-product-img-placeholder\"&gt;④&lt;/div&gt;\n                &lt;/div&gt;\n                &lt;p class=\"dior-product-label\"&gt;Váy &amp; Đầm&lt;/p&gt;\n                &lt;p class=\"dior-product-name\"&gt;Đầm Dự Tiệc Đỏ&lt;/p&gt;\n                &lt;p class=\"dior-product-price\"&gt;899.000 ₫&lt;/p&gt;\n            &lt;/div&gt;\n        &lt;/div&gt;\n    &lt;/div&gt;\n\n    &lt;!-- BANNER --&gt;\n    &lt;div class=\"dior-banner\"&gt;\n        &lt;div&gt;\n            &lt;h2 class=\"dior-banner-title\"&gt;Ưu Đãi Đặc Biệt&lt;/h2&gt;\n            &lt;p style=\"font-size:11px; letter-spacing:4px; color:#c9a96e; margin-bottom:32px; text-transform:uppercase;\"&gt;Giảm Đến 50% · Hàng Sale&lt;/p&gt;\n            &lt;a href=\"/hang-sale.html\" class=\"dior-btn\"&gt;Mua Ngay&lt;/a&gt;\n        &lt;/div&gt;\n    &lt;/div&gt;\n\n    &lt;!-- VALUES --&gt;\n    &lt;div class=\"dior-values\"&gt;\n        &lt;div&gt;\n            &lt;div class=\"dior-value-icon\"&gt;✦&lt;/div&gt;\n            &lt;h3 class=\"dior-value-title\"&gt;Chất Lượng Cao Cấp&lt;/h3&gt;\n            &lt;p class=\"dior-value-desc\"&gt;Mỗi sản phẩm được chọn lọc kỹ càng từ những chất liệu cao cấp nhất, mang đến sự thoải mái và sang trọng tuyệt đối.&lt;/p&gt;\n        &lt;/div&gt;\n        &lt;div&gt;\n            &lt;div class=\"dior-value-icon\"&gt;◈&lt;/div&gt;\n            &lt;h3 class=\"dior-value-title\"&gt;Giao Hàng Toàn Quốc&lt;/h3&gt;\n            &lt;p class=\"dior-value-desc\"&gt;Dịch vụ giao hàng nhanh chóng, an toàn đến tận tay khách hàng trên toàn quốc trong vòng 2-3 ngày làm việc.&lt;/p&gt;\n        &lt;/div&gt;\n        &lt;div&gt;\n            &lt;div class=\"dior-value-icon\"&gt;◇&lt;/div&gt;\n            &lt;h3 class=\"dior-value-title\"&gt;Đổi Trả 30 Ngày&lt;/h3&gt;\n            &lt;p class=\"dior-value-desc\"&gt;Chính sách đổi trả linh hoạt trong 30 ngày, đảm bảo sự hài lòng tuyệt đối của khách hàng với mọi sản phẩm.&lt;/p&gt;\n        &lt;/div&gt;\n    &lt;/div&gt;\n\n&lt;/div&gt;\n.page-wrapper .columns,\n.page-wrapper .page-main {\n    max-width: 100% !important;\n    padding: 0 !important;\n}\n\n.page-layout-1column .column.main {\n    max-width: 100% !important;\n    padding: 0 !important;\n}</div>','any','2026-03-18 17:36:17','2026-03-18 17:36:17'),(4,'new','.template-managernew69bc1155bee56.jpg','<div class=\"full-width\" data-content-type=\"html\" data-appearance=\"default\" data-element=\"main\">&lt;style&gt;\n@import url(\'https://fonts.googleapis.com/css2?family=Cormorant+Garamond:wght@300;400;500;600&amp;family=Montserrat:wght@200;300;400;500&amp;display=swap\');\n\n* { margin: 0; padding: 0; box-sizing: border-box; }\n\n.dior-home {\n    font-family: \'Montserrat\', sans-serif;\n    color: #1a1a1a;\n    background: #fff;\n}\n\n/* HERO */\n.dior-hero {\n    position: relative;\n    height: 100vh;\n    background: #1a1a1a;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    overflow: hidden;\n}\n\n.dior-hero-bg {\n    position: absolute;\n    inset: 0;\n    background: linear-gradient(135deg, #1a1a1a 0%, #2d2d2d 50%, #1a1a1a 100%);\n}\n\n.dior-hero-content {\n    position: relative;\n    text-align: center;\n    color: #fff;\n    z-index: 2;\n}\n\n.dior-hero-subtitle {\n    font-family: \'Montserrat\', sans-serif;\n    font-size: 11px;\n    letter-spacing: 6px;\n    text-transform: uppercase;\n    color: #c9a96e;\n    margin-bottom: 24px;\n}\n\n.dior-hero-title {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: clamp(60px, 10vw, 120px);\n    font-weight: 300;\n    letter-spacing: 15px;\n    text-transform: uppercase;\n    line-height: 1;\n    margin-bottom: 32px;\n}\n\n.dior-hero-desc {\n    font-size: 12px;\n    letter-spacing: 3px;\n    text-transform: uppercase;\n    color: #ccc;\n    margin-bottom: 48px;\n}\n\n.dior-btn {\n    display: inline-block;\n    padding: 16px 48px;\n    border: 1px solid #c9a96e;\n    color: #c9a96e;\n    font-size: 10px;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n    text-decoration: none;\n    transition: all 0.4s ease;\n    cursor: pointer;\n    background: transparent;\n}\n\n.dior-btn:hover {\n    background: #c9a96e;\n    color: #1a1a1a;\n}\n\n.dior-btn-dark {\n    border-color: #1a1a1a;\n    color: #1a1a1a;\n}\n\n.dior-btn-dark:hover {\n    background: #1a1a1a;\n    color: #fff;\n}\n\n/* MARQUEE */\n.dior-marquee {\n    background: #c9a96e;\n    padding: 14px 0;\n    overflow: hidden;\n    white-space: nowrap;\n}\n\n.dior-marquee-text {\n    display: inline-block;\n    animation: marquee 20s linear infinite;\n    font-size: 10px;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n    color: #fff;\n}\n\n@keyframes marquee {\n    0% { transform: translateX(0); }\n    100% { transform: translateX(-50%); }\n}\n\n/* SECTION */\n.dior-section {\n    padding: 100px 60px;\n}\n\n.dior-section-title {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: clamp(36px, 5vw, 64px);\n    font-weight: 300;\n    letter-spacing: 8px;\n    text-transform: uppercase;\n    text-align: center;\n    margin-bottom: 16px;\n}\n\n.dior-section-sub {\n    text-align: center;\n    font-size: 10px;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n    color: #999;\n    margin-bottom: 60px;\n}\n\n/* CATEGORIES GRID */\n.dior-grid {\n    display: grid;\n    grid-template-columns: repeat(3, 1fr);\n    gap: 2px;\n}\n\n.dior-grid-item {\n    position: relative;\n    overflow: hidden;\n    aspect-ratio: 3/4;\n    background: #f5f5f5;\n    cursor: pointer;\n}\n\n.dior-grid-item:first-child {\n    grid-row: span 2;\n    aspect-ratio: auto;\n}\n\n.dior-grid-bg {\n    width: 100%;\n    height: 100%;\n    object-fit: cover;\n    transition: transform 0.8s ease;\n}\n\n.dior-grid-item:hover .dior-grid-bg {\n    transform: scale(1.05);\n}\n\n.dior-grid-overlay {\n    position: absolute;\n    inset: 0;\n    background: linear-gradient(to top, rgba(0,0,0,0.7) 0%, transparent 60%);\n    display: flex;\n    flex-direction: column;\n    justify-content: flex-end;\n    padding: 32px;\n    color: #fff;\n}\n\n.dior-grid-label {\n    font-size: 9px;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n    color: #c9a96e;\n    margin-bottom: 8px;\n}\n\n.dior-grid-name {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 28px;\n    font-weight: 300;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n}\n\n/* FEATURED - 2 columns */\n.dior-featured {\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: 40px;\n    align-items: center;\n    padding: 100px 60px;\n    background: #f8f8f6;\n}\n\n.dior-featured-img {\n    aspect-ratio: 3/4;\n    background: linear-gradient(135deg, #e8e0d5, #d4c9ba);\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    overflow: hidden;\n}\n\n.dior-featured-img-placeholder {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 80px;\n    color: rgba(255,255,255,0.5);\n    font-weight: 300;\n}\n\n.dior-featured-content {\n    padding: 40px;\n}\n\n.dior-featured-label {\n    font-size: 9px;\n    letter-spacing: 5px;\n    text-transform: uppercase;\n    color: #c9a96e;\n    margin-bottom: 24px;\n}\n\n.dior-featured-title {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 48px;\n    font-weight: 300;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n    line-height: 1.2;\n    margin-bottom: 24px;\n}\n\n.dior-featured-desc {\n    font-size: 12px;\n    line-height: 2;\n    color: #666;\n    margin-bottom: 40px;\n    letter-spacing: 1px;\n}\n\n/* PRODUCTS */\n.dior-products {\n    display: grid;\n    grid-template-columns: repeat(4, 1fr);\n    gap: 24px;\n}\n\n.dior-product {\n    cursor: pointer;\n}\n\n.dior-product-img {\n    aspect-ratio: 3/4;\n    background: linear-gradient(135deg, #f0ebe4, #e8e0d5);\n    margin-bottom: 16px;\n    overflow: hidden;\n    position: relative;\n}\n\n.dior-product-img-placeholder {\n    width: 100%;\n    height: 100%;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 40px;\n    color: rgba(180,160,140,0.5);\n    transition: transform 0.6s ease;\n}\n\n.dior-product:hover .dior-product-img-placeholder {\n    transform: scale(1.05);\n}\n\n.dior-product-label {\n    font-size: 8px;\n    letter-spacing: 3px;\n    text-transform: uppercase;\n    color: #c9a96e;\n    margin-bottom: 6px;\n}\n\n.dior-product-name {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 18px;\n    font-weight: 400;\n    letter-spacing: 2px;\n    margin-bottom: 6px;\n}\n\n.dior-product-price {\n    font-size: 11px;\n    letter-spacing: 2px;\n    color: #666;\n}\n\n/* BANNER */\n.dior-banner {\n    height: 60vh;\n    background: linear-gradient(135deg, #1a1a1a, #2d2d2d);\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    text-align: center;\n    color: #fff;\n}\n\n.dior-banner-title {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: clamp(40px, 6vw, 80px);\n    font-weight: 300;\n    letter-spacing: 10px;\n    text-transform: uppercase;\n    margin-bottom: 24px;\n}\n\n/* VALUES */\n.dior-values {\n    display: grid;\n    grid-template-columns: repeat(3, 1fr);\n    gap: 60px;\n    padding: 100px 60px;\n    text-align: center;\n}\n\n.dior-value-icon {\n    font-size: 32px;\n    margin-bottom: 20px;\n    color: #c9a96e;\n}\n\n.dior-value-title {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 22px;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n    margin-bottom: 16px;\n}\n\n.dior-value-desc {\n    font-size: 11px;\n    line-height: 2;\n    color: #888;\n    letter-spacing: 1px;\n}\n\n/* DIVIDER */\n.dior-divider {\n    text-align: center;\n    padding: 40px;\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 24px;\n    color: #c9a96e;\n    letter-spacing: 8px;\n}\n\n@media (max-width: 768px) {\n    .dior-grid { grid-template-columns: 1fr 1fr; }\n    .dior-grid-item:first-child { grid-row: span 1; }\n    .dior-featured { grid-template-columns: 1fr; }\n    .dior-products { grid-template-columns: repeat(2, 1fr); }\n    .dior-values { grid-template-columns: 1fr; gap: 40px; }\n    .dior-section { padding: 60px 24px; }\n}\n&lt;/style&gt;\n\n&lt;div class=\"dior-home\"&gt;\n\n    &lt;!-- HERO --&gt;\n    &lt;div class=\"dior-hero\"&gt;\n        &lt;div class=\"dior-hero-bg\"&gt;&lt;/div&gt;\n        &lt;div class=\"dior-hero-content\"&gt;\n            &lt;p class=\"dior-hero-subtitle\"&gt;Bộ Sưu Tập Mới 2024&lt;/p&gt;\n            &lt;h1 class=\"dior-hero-title\"&gt;Fashion&lt;br&gt;Store&lt;/h1&gt;\n            &lt;p class=\"dior-hero-desc\"&gt;Thời Trang Cao Cấp · Phong Cách Đẳng Cấp&lt;/p&gt;\n            &lt;a href=\"/collections\" class=\"dior-btn\"&gt;Khám Phá Ngay&lt;/a&gt;\n        &lt;/