tter-spacing: 3px;\n    text-transform: uppercase;\n    color: #ccc;\n    margin-bottom: 48px;\n}\n\n.dior-btn {\n    display: inline-block;\n    padding: 16px 48px;\n    border: 1px solid #c9a96e;\n    color: #c9a96e;\n    font-size: 10px;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n    text-decoration: none;\n    transition: all 0.4s ease;\n    cursor: pointer;\n    background: transparent;\n}\n\n.dior-btn:hover {\n    background: #c9a96e;\n    color: #1a1a1a;\n}\n\n.dior-btn-dark {\n    border-color: #1a1a1a;\n    color: #1a1a1a;\n}\n\n.dior-btn-dark:hover {\n    background: #1a1a1a;\n    color: #fff;\n}\n\n/* MARQUEE */\n.dior-marquee {\n    background: #c9a96e;\n    padding: 14px 0;\n    overflow: hidden;\n    white-space: nowrap;\n}\n\n.dior-marquee-text {\n    display: inline-block;\n    animation: marquee 20s linear infinite;\n    font-size: 10px;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n    color: #fff;\n}\n\n@keyframes marquee {\n    0% { transform: translateX(0); }\n    100% { transform: translateX(-50%); }\n}\n\n/* SECTION */\n.dior-section {\n    padding: 100px 60px;\n}\n\n.dior-section-title {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: clamp(36px, 5vw, 64px);\n    font-weight: 300;\n    letter-spacing: 8px;\n    text-transform: uppercase;\n    text-align: center;\n    margin-bottom: 16px;\n}\n\n.dior-section-sub {\n    text-align: center;\n    font-size: 10px;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n    color: #999;\n    margin-bottom: 60px;\n}\n\n/* CATEGORIES GRID */\n.dior-grid {\n    display: grid;\n    grid-template-columns: repeat(3, 1fr);\n    gap: 2px;\n}\n\n.dior-grid-item {\n    position: relative;\n    overflow: hidden;\n    aspect-ratio: 3/4;\n    background: #f5f5f5;\n    cursor: pointer;\n}\n\n.dior-grid-item:first-child {\n    grid-row: span 2;\n    aspect-ratio: auto;\n}\n\n.dior-grid-bg {\n    width: 100%;\n    height: 100%;\n    object-fit: cover;\n    transition: transform 0.8s ease;\n}\n\n.dior-grid-item:hover .dior-grid-bg {\n    transform: scale(1.05);\n}\n\n.dior-grid-overlay {\n    position: absolute;\n    inset: 0;\n    background: linear-gradient(to top, rgba(0,0,0,0.7) 0%, transparent 60%);\n    display: flex;\n    flex-direction: column;\n    justify-content: flex-end;\n    padding: 32px;\n    color: #fff;\n}\n\n.dior-grid-label {\n    font-size: 9px;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n    color: #c9a96e;\n    margin-bottom: 8px;\n}\n\n.dior-grid-name {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 28px;\n    font-weight: 300;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n}\n\n/* FEATURED - 2 columns */\n.dior-featured {\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: 40px;\n    align-items: center;\n    padding: 100px 60px;\n    background: #f8f8f6;\n}\n\n.dior-featured-img {\n    aspect-ratio: 3/4;\n    background: linear-gradient(135deg, #e8e0d5, #d4c9ba);\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    overflow: hidden;\n}\n\n.dior-featured-img-placeholder {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 80px;\n    color: rgba(255,255,255,0.5);\n    font-weight: 300;\n}\n\n.dior-featured-content {\n    padding: 40px;\n}\n\n.dior-featured-label {\n    font-size: 9px;\n    letter-spacing: 5px;\n    text-transform: uppercase;\n    color: #c9a96e;\n    margin-bottom: 24px;\n}\n\n.dior-featured-title {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 48px;\n    font-weight: 300;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n    line-height: 1.2;\n    margin-bottom: 24px;\n}\n\n.dior-featured-desc {\n    font-size: 12px;\n    line-height: 2;\n    color: #666;\n    margin-bottom: 40px;\n    letter-spacing: 1px;\n}\n\n/* PRODUCTS */\n.dior-products {\n    display: grid;\n    grid-template-columns: repeat(4, 1fr);\n    gap: 24px;\n}\n\n.dior-product {\n    cursor: pointer;\n}\n\n.dior-product-img {\n    aspect-ratio: 3/4;\n    background: linear-gradient(135deg, #f0ebe4, #e8e0d5);\n    margin-bottom: 16px;\n    overflow: hidden;\n    position: relative;\n}\n\n.dior-product-img-placeholder {\n    width: 100%;\n    height: 100%;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 40px;\n    color: rgba(180,160,140,0.5);\n    transition: transform 0.6s ease;\n}\n\n.dior-product:hover .dior-product-img-placeholder {\n    transform: scale(1.05);\n}\n\n.dior-product-label {\n    font-size: 8px;\n    letter-spacing: 3px;\n    text-transform: uppercase;\n    color: #c9a96e;\n    margin-bottom: 6px;\n}\n\n.dior-product-name {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 18px;\n    font-weight: 400;\n    letter-spacing: 2px;\n    margin-bottom: 6px;\n}\n\n.dior-product-price {\n    font-size: 11px;\n    letter-spacing: 2px;\n    color: #666;\n}\n\n/* BANNER */\n.dior-banner {\n    height: 60vh;\n    background: linear-gradient(135deg, #1a1a1a, #2d2d2d);\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    text-align: center;\n    color: #fff;\n}\n\n.dior-banner-title {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: clamp(40px, 6vw, 80px);\n    font-weight: 300;\n    letter-spacing: 10px;\n    text-transform: uppercase;\n    margin-bottom: 24px;\n}\n\n/* VALUES */\n.dior-values {\n    display: grid;\n    grid-template-columns: repeat(3, 1fr);\n    gap: 60px;\n    padding: 100px 60px;\n    text-align: center;\n}\n\n.dior-value-icon {\n    font-size: 32px;\n    margin-bottom: 20px;\n    color: #c9a96e;\n}\n\n.dior-value-title {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 22px;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n    margin-bottom: 16px;\n}\n\n.dior-value-desc {\n    font-size: 11px;\n    line-height: 2;\n    color: #888;\n    letter-spacing: 1px;\n}\n\n/* DIVIDER */\n.dior-divider {\n    text-align: center;\n    padding: 40px;\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 24px;\n    color: #c9a96e;\n    letter-spacing: 8px;\n}\n\n@media (max-width: 768px) {\n    .dior-grid { grid-template-columns: 1fr 1fr; }\n    .dior-grid-item:first-child { grid-row: span 1; }\n    .dior-featured { grid-template-columns: 1fr; }\n    .dior-products { grid-template-columns: repeat(2, 1fr); }\n    .dior-values { grid-template-columns: 1fr; gap: 40px; }\n    .dior-section { padding: 60px 24px; }\n}\n&lt;/style&gt;\n\n&lt;div class=\"dior-home\"&gt;\n\n    &lt;!-- HERO --&gt;\n    &lt;div class=\"dior-hero\"&gt;\n        &lt;div class=\"dior-hero-bg\"&gt;&lt;/div&gt;\n        &lt;div class=\"dior-hero-content\"&gt;\n            &lt;p class=\"dior-hero-subtitle\"&gt;Bộ Sưu Tập Mới 2024&lt;/p&gt;\n            &lt;h1 class=\"dior-hero-title\"&gt;Fashion&lt;br&gt;Store&lt;/h1&gt;\n            &lt;p class=\"dior-hero-desc\"&gt;Thời Trang Cao Cấp · Phong Cách Đẳng Cấp&lt;/p&gt;\n            &lt;a href=\"/collections\" class=\"dior-btn\"&gt;Khám Phá Ngay&lt;/a&gt;\n        &lt;/div&gt;\n    &lt;/div&gt;\n\n    &lt;!-- MARQUEE --&gt;\n    &lt;div class=\"dior-marquee\"&gt;\n        &lt;span class=\"dior-marquee-text\"&gt;\n            ✦ THỜI TRANG CAO CẤP &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ PHONG CÁCH ĐẲng CẤP &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ CHẤT LƯỢNG VƯỢT TRỘI &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ GIAO HÀNG TOÀN QUỐC &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ ĐỔI TRẢ 30 NGÀY &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ THỜI TRANG CAO CẤP &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ PHONG CÁCH ĐẲNG CẤP &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ CHẤT LƯỢNG VƯỢT TRỘI &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ GIAO HÀNG TOÀN QUỐC &amp;nbsp;&amp;nbsp;&amp;nbsp; ✦ ĐỔI TRẢ 30 NGÀY &amp;nbsp;&amp;nbsp;&amp;nbsp;\n        &lt;/span&gt;\n    &lt;/div&gt;\n\n   &lt;!-- CATEGORIES --&gt;\n&lt;div class=\"dior-section\"&gt;\n    &lt;p class=\"dior-section-sub\"&gt;Danh Mục Sản Phẩm&lt