ns-serif;\n    font-size: 11px;\n    letter-spacing: 6px;\n    text-transform: uppercase;\n    color: #c9a96e;\n    margin-bottom: 24px;\n}\n\n.dior-hero-title {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: clamp(60px, 10vw, 120px);\n    font-weight: 300;\n    letter-spacing: 15px;\n    text-transform: uppercase;\n    line-height: 1;\n    margin-bottom: 32px;\n}\n\n.dior-hero-desc {\n    font-size: 12px;\n    letter-spacing: 3px;\n    text-transform: uppercase;\n    color: #ccc;\n    margin-bottom: 48px;\n}\n\n.dior-btn {\n    display: inline-block;\n    padding: 16px 48px;\n    border: 1px solid #c9a96e;\n    color: #c9a96e;\n    font-size: 10px;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n    text-decoration: none;\n    transition: all 0.4s ease;\n    cursor: pointer;\n    background: transparent;\n}\n\n.dior-btn:hover {\n    background: #c9a96e;\n    color: #1a1a1a;\n}\n\n.dior-btn-dark {\n    border-color: #1a1a1a;\n    color: #1a1a1a;\n}\n\n.dior-btn-dark:hover {\n    background: #1a1a1a;\n    color: #fff;\n}\n\n/* MARQUEE */\n.dior-marquee {\n    background: #c9a96e;\n    padding: 14px 0;\n    overflow: hidden;\n    white-space: nowrap;\n}\n\n.dior-marquee-text {\n    display: inline-block;\n    animation: marquee 20s linear infinite;\n    font-size: 10px;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n    color: #fff;\n}\n\n@keyframes marquee {\n    0% { transform: translateX(0); }\n    100% { transform: translateX(-50%); }\n}\n\n/* SECTION */\n.dior-section {\n    padding: 100px 60px;\n}\n\n.dior-section-title {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: clamp(36px, 5vw, 64px);\n    font-weight: 300;\n    letter-spacing: 8px;\n    text-transform: uppercase;\n    text-align: center;\n    margin-bottom: 16px;\n}\n\n.dior-section-sub {\n    text-align: center;\n    font-size: 10px;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n    color: #999;\n    margin-bottom: 60px;\n}\n\n/* CATEGORIES GRID */\n.dior-grid {\n    display: grid;\n    grid-template-columns: repeat(3, 1fr);\n    gap: 2px;\n}\n\n.dior-grid-item {\n    position: relative;\n    overflow: hidden;\n    aspect-ratio: 3/4;\n    background: #f5f5f5;\n    cursor: pointer;\n}\n\n.dior-grid-item:first-child {\n    grid-row: span 2;\n    aspect-ratio: auto;\n}\n\n.dior-grid-bg {\n    width: 100%;\n    height: 100%;\n    object-fit: cover;\n    transition: transform 0.8s ease;\n}\n\n.dior-grid-item:hover .dior-grid-bg {\n    transform: scale(1.05);\n}\n\n.dior-grid-overlay {\n    position: absolute;\n    inset: 0;\n    background: linear-gradient(to top, rgba(0,0,0,0.7) 0%, transparent 60%);\n    display: flex;\n    flex-direction: column;\n    justify-content: flex-end;\n    padding: 32px;\n    color: #fff;\n}\n\n.dior-grid-label {\n    font-size: 9px;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n    color: #c9a96e;\n    margin-bottom: 8px;\n}\n\n.dior-grid-name {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 28px;\n    font-weight: 300;\n    letter-spacing: 4px;\n    text-transform: uppercase;\n}\n\n/* FEATURED - 2 columns */\n.dior-featured {\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: 40px;\n    align-items: center;\n    padding: 100px 60px;\n    background: #f8f8f6;\n}\n\n.dior-featured-img {\n    aspect-ratio: 3/4;\n    background: linear-gradient(135deg, #e8e0d5, #d4c9ba);\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    overflow: hidden;\n}\n\n.dior-featured-img-placeholder {\n    font-family: \'Cormorant Garamond\', serif;\n    font-size: 80px;\n    color: rgba(255,255,255,0.5);\n    font-weight: 300;\n}\n\n.dior-featured-content {\n    padding: 40px;\n}\n\n.dior-featured-label {\n    font-size: 9px;\n    letter-spacing: 5px;\n    text-transform: uppercase;\n    color: #c9a96e;\n    margin-bottom: 24px;\n}\n\n.dior-featured-title {\n    font-family: \'Cormorant Garamond\', serif;\n    font-siz