ass=\"dior-value-desc\"&gt;Chính sách đổi trả linh hoạt trong 30 ngày, đảm bảo sự hài lòng tuyệt đối của khách hàng với mọi sản phẩm.&lt;/p&gt;\n        &lt;/div&gt;\n    &lt;/div&gt;\n\n&lt;/div&gt;\n.page-wrapper .columns,\n.page-wrapper .page-main {\n    max-width: 100% !important;\n    padding: 0 !important;\n}\n\n.page-layout-1column .column.main {\n    max-width: 100% !important;\n    padding: 0 !important;\n}\n/* FIX GRID SIZE */\n.dior-grid a {\n    display: contents !important;\n}\n/* SEARCH PLACEHOLDER */\n.block-search .input-text::placeholder {\n    content: \'Tìm kiếm sản phẩm...\' !important;\n    font-family: \'Montserrat\', sans-serif !important;\n    font-size: 11px !important;\n    letter-spacing: 2px !important;\n    color: #999 !important;\n}\n\n/* STYLE SEARCH BOX */\n.block-search .input-text {\n    border: none !important;\n    border-bottom: 1px solid #1a1a1a !important;\n    border-radius: 0 !important;\n    font-family: \'Montserrat\', sans-serif !important;\n    font-size: 11px !important;\n    letter-spacing: 2px !important;\n}</div><div data-content-type=\"text\" data-appearance=\"default\" data-element=\"main\"><p>12345</p></div></div></div></div>','any','2026-03-19 15:42:22','2026-03-19 15:42:22'),(11,'test2','.template-managertest269bc19ba88c00.jpg','<style>#html-body [data-pb-style=IHFMXYM]{border-width:1px}#html-body [data-pb-style=Y6BFHY4]{text-align:left}#html-body [data-pb-style=HDG9IWI]{border-width:1px;min-height:300px}#html-body [data-pb-style=S8YRSO9]{justify-content:flex-start;display:flex;flex-direction:column;background-position:left top;background-size:cover;background-repeat:no-repeat;background-attachment:scroll}</style><div class=\"tab-align-left\" data-content-type=\"tabs\" data-appearance=\"default\" data-active-tab=\"\" data-element=\"main\"><ul role=\"tablist\" class=\"tabs-navigation\" data-element=\"navigation\" data-pb-style=\"Y6BFHY4\"><li role=\"tab\" class=\"tab-header\" data-element=\"headers\" data-pb-style