v class=\"dior-grid-item\" onclick=\"window.location=\'/tui-xach.html\'\" style=\"cursor:pointer;\"&gt;\n            &lt;div class=\"dior-grid-bg\" style=\"background: linear-gradient(135deg, #c9a96e, #b8954a); height:100%; display:flex; align-items:center; justify-content:center;\"&gt;\n                &lt;span style=\"font-family:\'Cormorant Garamond\',serif; font-size:80px; color:rgba(255,255,255,0.3);\"&gt;&lt;/span&gt;\n            &lt;/div&gt;\n            &lt;div class=\"dior-grid-overlay\"&gt;\n                &lt;span class=\"dior-grid-label\"&gt;Phụ Kiện&lt;/span&gt;\n                &lt;span class=\"dior-grid-name\"&gt;Túi Xách&lt;/span&gt;\n            &lt;/div&gt;\n        &lt;/div&gt;\n\n        &lt;div class=\"dior-grid-item\" onclick=\"window.location=\'/giay-nam.html\'\" style=\"cursor:pointer;\"&gt;\n            &lt;div class=\"dior-grid-bg\" style=\"background: linear-gradient(135deg, #4a4a4a, #333); height:100%; display:flex; align-items:center; justify-content:center;\"&gt;\n                &lt;span style=\"font-family:\'Cormorant Garamond\',serif; font-size:80px; color:rgba(201,169,110,0.3);\"&gt;&lt;/span&gt;\n            &lt;/div&gt;\n            &lt;div class=\"dior-grid-overlay\"&gt;\n                &lt;span class=\"dior-grid-label\"&gt;Thời Trang&lt;/span&gt;\n                &lt;span class=\"dior-grid-name\"&gt;Giày Nam&lt;/span&gt;\n            &lt;/div&gt;\n        &lt;/div&gt;\n\n    &lt;/div&gt;\n&lt;/div&gt;\n\n    &lt;!-- FEATURED --&gt;\n    &lt;div class=\"dior-featured\"&gt;\n        &lt;div class=\"dior-featured-img\"&gt;\n            &lt;div class=\"dior-featured-img-placeholder\"&gt;✦&lt;/div&gt;\n        &lt;/div&gt;\n        &lt;div class=\"dior-featured-content\"&gt;\n            &lt;p class=\"dior-featured-label\"&gt;Nổi Bật · Mùa Thu Đông 2024&lt;/p&gt;\n            &lt;h2 class=\"dior-featured-title\"&gt;Bộ Sưu Tập&lt;br&gt;Đặc Biệt&lt;/h2&gt;\n            &lt;p class=\"dior-featured-desc\"&gt;\n                Được lấy